import { icon } from '@fortawesome/fontawesome-svg-core';
import { Wrench, Cpu, Settings2, HardDrive, Zap, LockKeyhole,Shield, Database, Briefcase, Headset } from 'lucide-react';

export const servicesData = [
  {
    icon: Wrench,
    price: '80',
    title: 'Limpeza Física Completa',
    description: 'Remoção total de poeira interna e externa, limpeza de coolers, ventoinhas e componentes para máxima eficiência de resfriamento.',
  },
  {
    icon: Cpu,
    price: '60',
    title: 'Troca de Pasta Térmica Premium',
    description: 'Aplicação de pasta térmica de alta qualidade para otimizar a transferência de calor e reduzir temperaturas do processador.',
  },
  {
    icon: Settings2,
    price: '120',
    title: 'Manutenção Completa',
    description: 'Limpeza física + troca de pasta térmica + verificação de componentes. Pacote completo para renovação total.',
  },
  {
    icon: Shield,
    price:'200',
    title
  }
];
